import { Menubar as KobalteMenubar } from "@kobalte/core/menubar";
import { Check, ChevronRight, Circle } from "lucide-solid";
import type { Component, ComponentProps, JSX } from "solid-js";
import { splitProps } from "solid-js";
import { cn } from "~/lib/utils";

const Menubar: Component<ComponentProps<typeof KobalteMenubar> & { class?: string }> = (props) => {
  const [local, rest] = splitProps(props, ["class"]);
  return (
    <KobalteMenubar
      class={cn(
        "flex h-10 items-center space-x-1 rounded-md border bg-background p-1",
        local.class,
      )}
      {...rest}
    />
  );
};

const MenubarMenu = KobalteMenubar.Menu;

const MenubarTrigger: Component<ComponentProps<typeof KobalteMenubar.Trigger>> = (props) => {
  const [local, rest] = splitProps(props, ["class"]);
  return (
    <KobalteMenubar.Trigger
      class={cn(
        "flex cursor-default select-none items-center rounded-sm px-3 py-1.5 text-sm font-medium outline-none",
        "focus:bg-accent focus:text-accent-foreground",
        "data-[expanded]:bg-accent data-[expanded]:text-accent-foreground",
        local.class,
      )}
      {...rest}
    />
  );
};

const MenubarContent: Component<ComponentProps<typeof KobalteMenubar.Content>> = (props) => {
  const [local, rest] = splitProps(props, ["class"]);
  return (
    <KobalteMenubar.Portal>
      <KobalteMenubar.Content
        class={cn(
          "z-50 min-w-[12rem] overflow-hidden rounded-md border bg-popover p-1 text-popover-foreground shadow-md",
          "data-[expanded]:animate-in data-[closed]:animate-out",
          "data-[closed]:fade-out-0 data-[expanded]:fade-in-0",
          "data-[closed]:zoom-out-95 data-[expanded]:zoom-in-95",
          local.class,
        )}
        {...rest}
      />
    </KobalteMenubar.Portal>
  );
};

const MenubarItem: Component<ComponentProps<typeof KobalteMenubar.Item> & { inset?: boolean }> = (
  props,
) => {
  const [local, rest] = splitProps(props, ["class", "inset"]);
  return (
    <KobalteMenubar.Item
      class={cn(
        "relative flex cursor-default select-none items-center rounded-sm px-2 py-1.5 text-sm outline-none",
        "focus:bg-accent focus:text-accent-foreground",
        "data-[disabled]:pointer-events-none data-[disabled]:opacity-50",
        local.inset && "pl-8",
        local.class,
      )}
      {...rest}
    />
  );
};

const MenubarSub = KobalteMenubar.Sub;

const MenubarSubTrigger: Component<
  ComponentProps<typeof KobalteMenubar.SubTrigger> & { inset?: boolean }
> = (props) => {
  const [local, rest] = splitProps(props, ["class", "inset", "children"]);
  return (
    <KobalteMenubar.SubTrigger
      class={cn(
        "flex cursor-default select-none items-center rounded-sm px-2 py-1.5 text-sm outline-none",
        "focus:bg-accent data-[expanded]:bg-accent",
        local.inset && "pl-8",
        local.class,
      )}
      {...rest}
    >
      {local.children}
      <ChevronRight class="ml-auto h-4 w-4" />
    </KobalteMenubar.SubTrigger>
  );
};

const MenubarSubContent: Component<ComponentProps<typeof KobalteMenubar.SubContent>> = (props) => {
  const [local, rest] = splitProps(props, ["class"]);
  return (
    <KobalteMenubar.SubContent
      class={cn(
        "z-50 min-w-[8rem] overflow-hidden rounded-md border bg-popover p-1 text-popover-foreground shadow-lg",
        "data-[expanded]:animate-in data-[closed]:animate-out data-[closed]:fade-out-0 data-[expanded]:fade-in-0",
        local.class,
      )}
      {...rest}
    />
  );
};

const MenubarCheckboxItem: Component<ComponentProps<typeof KobalteMenubar.CheckboxItem>> = (
  props,
) => {
  const [local, rest] = splitProps(props, ["class", "children"]);
  return (
    <KobalteMenubar.CheckboxItem
      class={cn(
        "relative flex cursor-default select-none items-center rounded-sm py-1.5 pl-8 pr-2 text-sm outline-none",
        "focus:bg-accent focus:text-accent-foreground",
        "data-[disabled]:pointer-events-none data-[disabled]:opacity-50",
        local.class,
      )}
      {...rest}
    >
      <span class="absolute left-2 flex h-3.5 w-3.5 items-center justify-center">
        <KobalteMenubar.ItemIndicator>
          <Check class="h-4 w-4" />
        </KobalteMenubar.ItemIndicator>
      </span>
      {local.children}
    </KobalteMenubar.CheckboxItem>
  );
};

const MenubarRadioGroup = KobalteMenubar.RadioGroup;

const MenubarRadioItem: Component<ComponentProps<typeof KobalteMenubar.RadioItem>> = (props) => {
  const [local, rest] = splitProps(props, ["class", "children"]);
  return (
    <KobalteMenubar.RadioItem
      class={cn(
        "relative flex cursor-default select-none items-center rounded-sm py-1.5 pl-8 pr-2 text-sm outline-none",
        "focus:bg-accent focus:text-accent-foreground",
        "data-[disabled]:pointer-events-none data-[disabled]:opacity-50",
        local.class,
      )}
      {...rest}
    >
      <span class="absolute left-2 flex h-3.5 w-3.5 items-center justify-center">
        <KobalteMenubar.ItemIndicator>
          <Circle class="h-2 w-2 fill-current" />
        </KobalteMenubar.ItemIndicator>
      </span>
      {local.children}
    </KobalteMenubar.RadioItem>
  );
};

const MenubarLabel: Component<JSX.HTMLAttributes<HTMLDivElement> & { inset?: boolean }> = (
  props,
) => {
  const [local, rest] = splitProps(props, ["class", "inset"]);
  return (
    <div
      class={cn("px-2 py-1.5 text-sm font-semibold", local.inset && "pl-8", local.class)}
      {...rest}
    />
  );
};

const MenubarSeparator: Component<ComponentProps<typeof KobalteMenubar.Separator>> = (props) => {
  const [local, rest] = splitProps(props, ["class"]);
  return <KobalteMenubar.Separator class={cn("-mx-1 my-1 h-px bg-muted", local.class)} {...rest} />;
};

const MenubarShortcut: Component<JSX.HTMLAttributes<HTMLSpanElement>> = (props) => {
  const [local, rest] = splitProps(props, ["class"]);
  return (
    <span
      class={cn("ml-auto text-xs tracking-widest text-muted-foreground", local.class)}
      {...rest}
    />
  );
};

export {
  Menubar,
  MenubarMenu,
  MenubarTrigger,
  MenubarContent,
  MenubarItem,
  MenubarSub,
  MenubarSubTrigger,
  MenubarSubContent,
  MenubarCheckboxItem,
  MenubarRadioGroup,
  MenubarRadioItem,
  MenubarLabel,
  MenubarSeparator,
  MenubarShortcut,
};
